import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useTable, useFilters, useGlobalFilter, useAsyncDebounce } from 'react-table';
import { Input, Button, Table, Space, Modal, Form, notification } from 'antd';

const { Search } = Input;
const { confirm } = Modal;

const DefaultColumnFilter = ({ column: { filterValue, preFilteredRows, setFilter } }) => {
  const count = preFilteredRows.length;

  return (
    <input
      value={filterValue || ''}
      onChange={(e) => {
        setFilter(e.target.value || undefined);
      }}
      placeholder={`Search (${count} ${count === 1 ? 'result' : 'results'})`}
    />
  );
};

function MaterialList() {
  const [material, setMaterial] = useState([]);
  const [newMaterialData, setNewMaterialData] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: '',
  });
  const [editMaterialData, setEditMaterialData] = useState(null);
  const [isAddModalVisible, setIsAddModalVisible] = useState(false);
  const [isEditModalVisible, setIsEditModalVisible] = useState(false);

  useEffect(() => {
    fetchMaterial();
  }, []);

  const fetchMaterial = () => {
    axios
      .get('http://localhost:8081')
      .then((res) => setMaterial(res.data))
      .catch((err) => console.log(err));
  };

  const handleAddMaterial = () => {
    axios
      .post('http://localhost:8081', newMaterialData)
      .then((res) => {
        setMaterial((prevMaterial) => [...prevMaterial, res.data]);
        setNewMaterialData({
          matid: '',
          name: '',
          description: '',
          unit_of_measure: '',
          price_per_unit: 0,
          recent_vendor: '',
        });
        setIsAddModalVisible(false);
        notification.success({ message: 'Material added successfully' });
      })
      .catch((err) => console.log(err));
  };

  const handleEditMaterial = () => {
    const { id } = editMaterialData;
    axios
      .put(`http://localhost:8081/${id}`, editMaterialData)
      .then(() => {
        const updatedMaterial = material.map((m) => (m.id === id ? editMaterialData : m));
        setMaterial(updatedMaterial);
        setEditMaterialData(null);
        setIsEditModalVisible(false);
        notification.success({ message: 'Material updated successfully' });
      })
      .catch((err) => console.log(err));
  };

  const handleDeleteMaterial = useCallback((id) => {
    confirm({
      title: 'Delete Material',
      content: 'Are you sure you want to delete this material?',
      okText: 'Delete',
      okType: 'danger',
      cancelText: 'Cancel',
      onOk() {
        axios
          .delete(`http://localhost:8081/${id}`)
          .then(() => {
            const updatedMaterial = material.filter((m) => m.id !== id);
            setMaterial(updatedMaterial);
            notification.success({ message: 'Material deleted successfully' });
          })
          .catch((err) => console.log(err));
      },
    });
  }, [material]);

  const handleInputChange = (e, type) => {
    const { name, value } = e.target;
    const data = { ...type };
    data[name] = value;
    if (type === newMaterialData) {
      setNewMaterialData(data);
    } else if (type === editMaterialData) {
      setEditMaterialData(data);
    }
  };

  const columns = [
    {
      Header: 'ID',
      accessor: 'matid',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Name',
      accessor: 'name',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Description',
      accessor: 'description',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Unit of Measure',
      accessor: 'unit_of_measure',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Price per Unit',
      accessor: 'price_per_unit',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Recent Vendor',
      accessor: 'recent_vendor',
      Filter: DefaultColumnFilter, // Apply the DefaultColumnFilter component for filtering
    },
    {
      Header: 'Actions',
      Cell: ({ row }) => (
        <Space size="middle">
          <Button type="primary" onClick={() => handleEditClick(row.original)}>
            Edit
          </Button>
          <Button type="primary" danger onClick={() => handleDeleteMaterial(row.original.id)}>
            Delete
          </Button>
        </Space>
      ),
    },
  ];

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    state,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: material,
      initialState: { pageIndex: 0 },
    },
    useFilters,
    useGlobalFilter
  );

  const { globalFilter } = state;

  const handleGlobalFilterChange = useAsyncDebounce((value) => {
    setGlobalFilter(value || undefined);
  }, 200);

  const handleAddClick = () => {
    setIsAddModalVisible(true);
  };

  const handleEditClick = (data) => {
    setEditMaterialData(data);
    setIsEditModalVisible(true);
  };

  const handleAddModalCancel = () => {
    setIsAddModalVisible(false);
  };

  const handleEditModalCancel = () => {
    setIsEditModalVisible(false);
  };

  return (
    <div>
      <div className="table-toolbar">
        <Button type="primary" onClick={handleAddClick}>
          Add Material
        </Button>
        <Search
          placeholder="Search materials"
          allowClear
          value={globalFilter || ''}
          onChange={(e) => handleGlobalFilterChange(e.target.value)}
          style={{ width: 200, float: 'right' }}
        />
      </div>
      <Table {...getTableProps()} dataSource={rows} rowKey="id">
        {headerGroups.map((headerGroup) => (
          <Table.ColumnGroup {...headerGroup.getHeaderGroupProps()}>
            {headerGroup.headers.map((column) => (
              <Table.Column {...column.getHeaderProps()}>{column.render('Header')}</Table.Column>
            ))}
          </Table.ColumnGroup>
        ))}
        <Table.Body {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <Table.Row {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <Table.Cell {...cell.getCellProps()}>{cell.render('Cell')}</Table.Cell>
                ))}
              </Table.Row>
            );
          })}
        </Table.Body>
      </Table>
      <Modal
        title="Add Material"
        visible={isAddModalVisible}
        onOk={handleAddMaterial}
        onCancel={handleAddModalCancel}
      >
        <Form>
          {/* Add Material form fields */}
        </Form>
      </Modal>
      <Modal
        title="Edit Material"
        visible={isEditModalVisible}
        onOk={handleEditMaterial}
        onCancel={handleEditModalCancel}
      >
        <Form>
          {/* Edit Material form fields */}
        </Form>
      </Modal>
    </div>
  );
}

export default MaterialList;
